package ui.admin;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import controller.*;import model.*;import util.*;import ui.common.TableStyle;
public class ReportsPanel extends JPanel{ JTable table=new JTable(); public ReportsPanel(){setBackground(UITheme.BG);setLayout(new BorderLayout());add(UITheme.title("Manage Reports"),BorderLayout.NORTH);add(new JScrollPane(table),BorderLayout.CENTER);JButton close=UITheme.button("Close Report");add(close,BorderLayout.SOUTH);close.addActionListener(e->close());load();} void load(){DefaultTableModel m=new DefaultTableModel(new Object[]{"ID","User","Internship","Reason","Status","Date"},0);for(Report r:new ReportController().all())m.addRow(new Object[]{r.getId(),r.getUserId(),r.getJobId(),r.getReason(),r.getStatus(),r.getCreatedAt()});table.setModel(m);TableStyle.apply(table);} void close(){int r=table.getSelectedRow();if(r<0)return;new ReportController().close(Integer.parseInt(table.getValueAt(r,0).toString()));load();}}
